interface OrderRepository {
    void save(OrderRecord record);
    OrderRecord findByOrderId(String orderId);
}

class InMemoryOrderRepository implements OrderRepository {
    private final Map<String, OrderRecord> store = Collections.synchronizedMap(new LinkedHashMap<>());

    @Override
    public void save(OrderRecord record) {
        if (record == null || record.orderId == null) throw new IllegalArgumentException("record/orderId required");
        store.put(record.orderId, record);
    }

    @Override
    public OrderRecord findByOrderId(String orderId) {
        if (orderId == null) return null;
        return store.get(orderId);
    }
}

class OrderRecord {
    String orderId;
    String buyerId;
    String currency;
    BigDecimal total;
    int totalQuantity;
    String status;
    String confirmationId;
    long createdAtEpochMillis;
    List<OrderItemRecord> items;
}

